const readings = [23, 45, 12, 67, 89, 34];
let total = 0;

// Use a for...of loop to sum all readings
// Your code here

challenges.solution:
const readings = [23, 45, 12, 67, 89, 34];
let total = 0;

for (const reading of readings) {
  total += reading;
}

